import{_ as t,c as a,o as e,aK as d}from"./chunks/framework.gpVTZwhR.js";const h=JSON.parse('{"title":"01_动词后面接 to do 还是 doing","description":"","frontmatter":{},"headers":[{"level":2,"title":"看 to 是不是不定式","slug":"看-to-是不是不定式","link":"#看-to-是不是不定式","children":[]},{"level":2,"title":"看 to 是否是介词","slug":"看-to-是否是介词","link":"#看-to-是否是介词","children":[]}],"relativePath":"gaozhong/英语/总结文章/单词句子语法辨析/01_动词后面接 to do 还是 doing.md","filePath":"gaozhong/英语/总结文章/单词句子语法辨析/01_动词后面接 to do 还是 doing.md","lastUpdated":1740235486000}'),n={name:"gaozhong/英语/总结文章/单词句子语法辨析/01_动词后面接 to do 还是 doing.md"};function i(l,o,r,_,p,s){return e(),a("div",null,o[0]||(o[0]=[d('<h1 id="_01-动词后面接-to-do-还是-doing" tabindex="-1">01_动词后面接 to do 还是 doing <a class="header-anchor" href="#_01-动词后面接-to-do-还是-doing" aria-label="Permalink to &quot;01_动词后面接 to do 还是 doing&quot;">​</a></h1><h2 id="看-to-是不是不定式" tabindex="-1">看 to 是不是不定式 <a class="header-anchor" href="#看-to-是不是不定式" aria-label="Permalink to &quot;看 to 是不是不定式&quot;">​</a></h2><p>to do 也就是不定式，表示目的和将来，所描述的事情 <strong>即将发生或还没有发生</strong>。</p><p>而 doing 强调做这件事的过程，它往往是把动作变成了一件事。</p><p>所以只要记住事情将要发生或还没发生，用 to do，</p><p>把动作变成一件事情，就用 doing。</p><p>例如：</p><p>我计划去打篮球：</p><p>I plan to play basketball。我计划去打篮球（还没发生）</p><p>I like playing basketball。我喜欢打篮球（一件事）</p><h2 id="看-to-是否是介词" tabindex="-1">看 to 是否是介词 <a class="header-anchor" href="#看-to-是否是介词" aria-label="Permalink to &quot;看 to 是否是介词&quot;">​</a></h2><p>又如 look forward to doing。look 是看，forward 是向前，字面意思向前看，所以 to 代表的是朝着某个方向，那么 to 就是介词，而不是不定式。所以接 doing。</p><p>往前看，翘首以待，希望……</p>',13)]))}const c=t(n,[["render",i]]);export{h as __pageData,c as default};
